import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

export const Schema = z.object({
  时间: z.object({
    日期: z.string(),
    时段: z.string(),
    星期: z.string()
  }),

  郑怡云: z.object({
    攻略阶段: z.coerce.number().transform(v => _.clamp(v, 0, 200)),
    当前位置: z.string(),
    对user态度: z.string(),
    警惕程度: z.coerce.number().transform(v => _.clamp(v, 0, 100)),
    身体开放度: z.coerce.number().transform(v => _.clamp(v, 0, 100)),
    是否怀孕: z.boolean(),
    婚姻状态: z.string()
  }),

  安诺: z.object({
    身份状态: z.string(),
    计划阶段: z.string(),
    与user好感: z.coerce.number().transform(v => _.clamp(v, 0, 100)),
    处女状态: z.boolean(),
    当前位置: z.string(),
    情绪稳定度: z.coerce.number().transform(v => _.clamp(v, 0, 100))
  }),

  家庭: z.object({
    父母婚姻: z.string(),
    家庭居住: z.string(),
    安诺入住: z.boolean()
  }),

  user: z.object({
    当前位置: z.string(),
    生理状态: z.string(),
    学业阶段: z.string()
  }),

  陆依依: z.object({
    关系状态: z.string(),
    是否怀孕: z.boolean()
  }),

  蓉阿姨: z.object({
    发生过关系: z.boolean()
  }),

  凌小北: z.object({
    互动度: z.coerce.number().transform(v => _.clamp(v, 0, 100))
  })
});

$(() => {
  registerMvuSchema(Schema);
})
